import {
  css,
  html,
  customElement,
  state,
  LitElement,
  when,
  repeat,
} from "@umbraco-cms/backoffice/external/lit";
import { UmbElementMixin } from "@umbraco-cms/backoffice/element-api";
import { UmbWorkspaceViewElement } from "@umbraco-cms/backoffice/workspace";
import type {
  FieldPreValueSource,
  PreValue,
  PreValueSourceTypeWithSettings,
} from "@umbraco-forms/generated";
import type { UmbInputRadioButtonListElement } from "@umbraco-cms/backoffice/components";
import type {
  UmbPropertyDatasetElement,
  UmbPropertyValueData,
} from "@umbraco-cms/backoffice/property";
import type { UmbPropertyEditorConfig } from "@umbraco-cms/backoffice/property-editor";
import type { UUIRadioEvent } from "@umbraco-ui/uui";
import type { UUISelectEvent } from "@umbraco-cms/backoffice/external/uui";
import { FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT } from "../../prevaluesource-workspace.context-token.js";
import { ProviderTypeSettingsHelper } from "../../../../provider-types/provider-type-settings-helper.class.js";

const elementName = "workspace-view-prevaluesource-design";

@customElement(elementName)
export class UmbWorkspaceViewPrevalueSourceDesignElement
  extends UmbElementMixin(LitElement)
  implements UmbWorkspaceViewElement
{
  #cacheOptions: UmbInputRadioButtonListElement["list"] = [];

  @state()
  _prevalueSource?: FieldPreValueSource;

  @state()
  _prevalueSourceType?: PreValueSourceTypeWithSettings;

  @state()
  _settingValues: Array<UmbPropertyValueData> = [];

  @state()
  _settingsConfig: Array<{ alias: string; value: UmbPropertyEditorConfig }> = [];

  @state()
  _settingsConfigLoaded: boolean = false;;

  @state()
  _cachePrevaluesOption: string = "";

  @state()
  _cachePrevaluesByTimeValue: number = 0;

  @state()
  _cachePrevaluesByTimeUnit: "seconds" | "minutes" | "hours" = "seconds";

  #workspaceContext?: typeof FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT.TYPE;

  #providerTypeSettingsHelper?: ProviderTypeSettingsHelper;

  #init: Promise<unknown>;

  constructor() {
    super();

    this.#init = Promise.all([
      this.consumeContext(
        FORMS_PREVALUESOURCE_WORKSPACE_CONTEXT,
        (instance) => {
          this.#workspaceContext = instance;
          this.#observePrevalues();
        }
      ).asPromise(),
    ]);
  }

  #observePrevalues() {
    if (!this.#workspaceContext) return;
    this.observe(this.#workspaceContext.prevalues, () => {
      this.requestUpdate();
    });
  }

  async connectedCallback() {
    super.connectedCallback();

    await this.#init;
    if (!this.#workspaceContext) return;

    this._prevalueSource = this.#workspaceContext.getData();

    const prevalueSourceTypeId =
      this._prevalueSource?.fieldPreValueSourceTypeId;
    if (!prevalueSourceTypeId) return;

    this._prevalueSourceType =
      await this.#workspaceContext?.loadPrevalueSourceType(
        prevalueSourceTypeId
      );
    if (!this._prevalueSourceType) return;

    this.#providerTypeSettingsHelper = new ProviderTypeSettingsHelper(
      this,
      this._prevalueSourceType,
      "formProviderPrevalueSources"
    );

    await this.#providerTypeSettingsHelper.loadSettingValueConverterApis();
    await this.#initialize();
  }

  async #initialize() {
    if (!this.#workspaceContext || !this._prevalueSource) return;

    this.#initCacheOptions();

    this._settingValues =
      await this.#providerTypeSettingsHelper!.getSettingValues(
        this._prevalueSource.settings
      );

    this._settingsConfig =
      await this.#providerTypeSettingsHelper!.getSettingsConfig(
        this._settingValues,
        this._prevalueSourceType!.settings
      );
    this._settingsConfigLoaded = true;

    // Initialize settings based on configured default values.
    if (this.#workspaceContext?.getIsNew() && this._prevalueSourceType) {
      const settings = structuredClone(this._prevalueSourceType.settings);
      for (let i = 0; i < this._prevalueSourceType!.settings.length; i++) {
        const setting = this._prevalueSourceType!.settings[i];
        if (setting.defaultValue) {
          settings[setting.alias] = setting.defaultValue;
        }
      }

      this._settingValues = settings;
    }

    if (this._cachePrevaluesOption === "") {
      this.#initCacheOptionsValue();
    }
  }

  async #onSettingsChange(e: CustomEvent) {
    const value = (e.target as UmbPropertyDatasetElement).value;
    this._settingValues = value;

    const settings =
      await this.#providerTypeSettingsHelper!.getUpdatedSettingsForPersistence(
        value
      );

    this.#setPropertyValue("settings", settings);
  }

  #onCacheOptionsChange(event: UUIRadioEvent) {
    event.stopPropagation();
    if (event.target.tagName !== "UUI-RADIO") return;
    this._cachePrevaluesOption = event.target.value;
    this.#updateCacheOptionsValue();
  }

  #initCacheOptions() {
    this.#cacheOptions = [
      {
        label: this.localize.term("formPrevalueSources_cacheOptionsNone"),
        value: "none",
      },
      {
        label: this.localize.term("formPrevalueSources_cacheOptionsTime"),
        value: "time",
      },
      {
        label: this.localize.term("formPrevalueSources_cacheOptionsNoExpiry"),
        value: "noExpiry",
      },
    ];
  }

  #initCacheOptionsValue() {
    const value = this._prevalueSource?.cachePrevaluesFor.toString();

    if (value) {
      if (value[0] === "-") {
        this._cachePrevaluesOption = "noExpiry";
      } else if (value === "00:00:00") {
        this._cachePrevaluesOption = "none";
      } else {
        this._cachePrevaluesOption = "time";

        const timeSpanParts = value.split(":");
        if (parseInt(timeSpanParts[0]) > 0) {
          this._cachePrevaluesByTimeValue = parseInt(timeSpanParts[0]);
          this._cachePrevaluesByTimeUnit = "hours";
        } else if (parseInt(timeSpanParts[1]) > 0) {
          this._cachePrevaluesByTimeValue = parseInt(timeSpanParts[1]);
          this._cachePrevaluesByTimeUnit = "minutes";
        } else {
          this._cachePrevaluesByTimeValue = parseInt(timeSpanParts[2]);
          this._cachePrevaluesByTimeUnit = "seconds";
        }
      }
    } else {
      this._cachePrevaluesOption = "noExpiry";
    }
  }

  #updateCacheOptionsValue() {
    let value = "";
    switch (this._cachePrevaluesOption) {
      case "none":
        value = "00:00:00.0000000";
        break;
      case "time":
        value = this.#getTimeSpan();
        break;
      case "noExpiry":
        value = "-00:00:00.0010000";
        break;
    }
    this.#setPropertyValue("cachePrevaluesFor", value);
  }

  #getTimeSpan() {
    const value = this._cachePrevaluesByTimeValue;
    const unit = this._cachePrevaluesByTimeUnit;
    const timeSpan = new Date(
      value *
        1000 *
        (unit === "minutes" || unit === "hours" ? 60 : 1) *
        (unit === "hours" ? 60 : 1)
    )
      .toISOString()
      .slice(11, 19);
    return timeSpan;
  }

  #onCacheOptionsTimeValueChange(e: CustomEvent) {
    const value = (e.target as HTMLInputElement).value;
    this._cachePrevaluesByTimeValue = parseInt(value);
    this.#updateCacheOptionsValue();
  }

  #onCacheOptionsTimeUnitChange(e: UUISelectEvent) {
    const selectedValue = e.target.value.toString() as
      | "seconds"
      | "minutes"
      | "hours";
    this._cachePrevaluesByTimeUnit = selectedValue;
    this.#updateCacheOptionsValue();
  }

  #setPropertyValue(alias: string, value: unknown) {
    this.#workspaceContext?.setPrevalueSourceProperty(alias, value);
    this.dispatchEvent(new CustomEvent("valueChange"));
  }

  render() {
    return html`
      <uui-box
        headline=${this.localize.term(
          "formPrevalueSources_designModalHeadline"
        )}
      >
        <umb-property-layout
          alias="type"
          .label=${this.localize.term("general_type")}
        >
          <div slot="editor">${this._prevalueSourceType?.name}</div>
        </umb-property-layout>

        ${when(
          this.#providerTypeSettingsHelper && this._prevalueSourceType && this._settingsConfigLoaded,
          () => html`<umb-property-dataset
            .value=${this._settingValues}
            @change=${this.#onSettingsChange}
          >
            ${this._prevalueSourceType!.settings.map(
              (setting) => html`
                <umb-property
                  ?inert=${setting.isReadOnly}
                  .label=${this.#providerTypeSettingsHelper?.getLocalizedSettingDetail(
                    setting,
                    "Label",
                    setting.name
                  )}
                  .description=${this.#providerTypeSettingsHelper?.getLocalizedSettingDetail(
                    setting,
                    "Description",
                    setting.description
                  )}
                  alias=${setting.alias}
                  .config=${this.#providerTypeSettingsHelper!.getPropertyConfigForSetting(
                    this._settingsConfig,
                    setting
                  )}
                  .appearance=${this.#providerTypeSettingsHelper!.getPropertyAppearanceForSetting(
                    setting.view
                  )}
                  property-editor-ui-alias=${setting.view}
                >
                </umb-property>
              `
            )}
          </umb-property-dataset> `
        )}

        <umb-property-layout
          alias="_cachePrevalues"
          .label=${this.localize.term("formPrevalueSources_cacheOptionsLabel")}
          .description=${this.localize.term(
            "formPrevalueSources_cacheOptionsDescription"
          )}
        >
          <div slot="editor">
            <uui-radio-group
              .value=${this._cachePrevaluesOption}
              @change=${this.#onCacheOptionsChange}
            >
              ${repeat(
                this.#cacheOptions,
                (item) => item,
                (item) =>
                  html`<uui-radio
                    value=${item.value}
                    label=${item.label}
                  ></uui-radio>`
              )}
            </uui-radio-group>
            ${when(
              this._cachePrevaluesOption === "time",
              () => html`
                <div>
                  <label
                    >${this.localize.term(
                      "formPrevalueSources_cacheOptionsEnterTime"
                    )}</label
                  >
                  <uui-input
                    type="number"
                    value=${this._cachePrevaluesByTimeValue}
                    min="1"
                    max="59"
                    label="Time value"
                    @change=${this.#onCacheOptionsTimeValueChange}
                  ></uui-input>
                  <uui-select
                    label="Time unit"
                    @change=${this.#onCacheOptionsTimeUnitChange}
                    .options=${["Seconds", "Minutes", "Hours"].map((o) => ({
                      name: this.localize.term(
                        `formPrevalueSources_cacheOptions${o}`
                      ),
                      value: o.toLowerCase(),
                      selected:
                        this._cachePrevaluesByTimeUnit === o.toLowerCase(),
                    }))}
                  ></uui-select>
                </div>
              `
            )}
          </div>
        </umb-property-layout>
      </uui-box>

      ${when(
        this.#workspaceContext && this.#workspaceContext.getPrevalues().length > 0,
        () => html`
          <uui-box
            headline=${this.localize.term("formPrevalueSources_listHeadline")}
          >
            <uui-table>
              <uui-table-head>
                <uui-table-head-cell
                  >${this.localize.term("general_value")}</uui-table-head-cell
                >
                <uui-table-head-cell
                  >${this.localize.term(
                    "formPrevalues_caption"
                  )}</uui-table-head-cell
                >
              </uui-table-head>
              ${this.#workspaceContext?.getPrevalues().map(
                (pv) => html` <uui-table-row>
                  <uui-table-cell>${pv.value}</uui-table-cell>
                  <uui-table-cell>${pv.caption}</uui-table-cell>
                </uui-table-row>`
              )}
            </uui-table>
          </uui-box>`
      )}
    `;
  }

  static styles = [
    css`
      :host {
        display: block;
        padding: var(--uui-size-layout-1);
      }

      uui-box + uui-box {
        margin-top: var(--uui-size-layout-1);
      }

      [inert] {
        opacity: 0.5;
      }
    `,
  ];
}

export default UmbWorkspaceViewPrevalueSourceDesignElement;

declare global {
  interface HTMLElementTagNameMap {
    [elementName]: UmbWorkspaceViewPrevalueSourceDesignElement;
  }
}
